    private fun performCacheCleanup(intent: Intent): Boolean {
        val cleanupLevel = intent.getIntExtra(EXTRA_CLEANUP_LEVEL, CLEANUP_LEVEL_LIGHT)
        val maxAgeDays = intent.getIntExtra(EXTRA_MAX_AGE_DAYS, 30)

        Log.i(TAG, "Starting cache cleanup - Level: $cleanupLevel, MaxAge: $maxAgeDays days")

        return try {
            // Clean internal cache
            val cacheDir = cacheDir
            if (cacheDir.exists()) {
                val cutoffTime = System.currentTimeMillis() - (maxAgeDays.toLong() * 24 * 60 * 60 * 1000)
                var deletedCount = 0
                var deletedSize = 0L

                cacheDir.listFiles()?.forEach { file ->
                    if (file.lastModified() < cutoffTime) {
                        val fileSize = file.length()
                        if (file.isDirectory) {
                            if (cleanupLevel >= CLEANUP_LEVEL_MODERATE) {
                                file.deleteRecursively()
                                deletedCount++
                                deletedSize += fileSize
                            }
                        } else {
                            file.delete()
                            deletedCount++
                            deletedSize += fileSize
                        }
                    }
                }

                // Aggressive cleanup: also clean external cache
                if (cleanupLevel >= CLEANUP_LEVEL_AGGRESSIVE) {
                    externalCacheDir?.listFiles()?.forEach { file ->
                        if (file.lastModified() < cutoffTime) {
                            val fileSize = file.length()
                            if (file.isDirectory) {
