                            }
                            deletedCount++
                            deletedSize += fileSize
                        }
                    }
                }

                Log.i(TAG, "Cache cleanup completed: $deletedCount files, ${deletedSize / 1024}KB freed")
            }
            true
        } catch (e: Exception) {
