                val cutoffTime = System.currentTimeMillis() - (maxAgeDays.toLong() * 24 * 60 * 60 * 1000)
                var deletedCount = 0

                logDir.listFiles()?.filter { it.name.endsWith(".log") || it.name.endsWith(".txt") }
                    ?.forEach { file ->
                        if (file.lastModified() < cutoffTime) {
                            file.delete()
                            deletedCount++
