                // Aggressive: delete all logs
                if (cleanupLevel >= CLEANUP_LEVEL_AGGRESSIVE) {
                    logDir.listFiles()?.forEach { it.delete() }
                    Log.d(TAG, "All logs deleted (aggressive cleanup)")
                }

                Log.i(TAG, "Log cleanup completed: $deletedCount files removed")
