        // Cache cleanup
        updateNotification("Full maintenance: Cleaning cache...")
        val cacheIntent = Intent(intent).apply {
            putExtra(EXTRA_CLEANUP_LEVEL, CLEANUP_LEVEL_MODERATE)
            putExtra(EXTRA_MAX_AGE_DAYS, 14)
        }
        if (!performCacheCleanup(cacheIntent)) {
            Log.w(TAG, "Cache cleanup failed during full maintenance")
            allSuccessful = false
        }

        // Log cleanup
        updateNotification("Full maintenance: Cleaning logs...")
        val logIntent = Intent(intent).apply {
            putExtra(EXTRA_CLEANUP_LEVEL, CLEANUP_LEVEL_MODERATE)
            putExtra(EXTRA_MAX_AGE_DAYS, 7)
        }
        if (!performLogCleanup(logIntent)) {
            Log.w(TAG, "Log cleanup failed during full maintenance")
            allSuccessful = false
        }

        // DB optimization
        updateNotification("Full maintenance: Optimizing database...")
        if (!performDbOptimization()) {
            Log.w(TAG, "DB optimization failed during full maintenance")
            allSuccessful = false
        }

        Log.i(TAG, "Full maintenance completed. All successful: $allSuccessful")
        return allSuccessful
    }

    /**
     * Sends a callback result to the calling app via broadcast.
     */
    private fun sendCallbackResult(intent: Intent, success: Boolean, message: String) {
        val callbackAction = intent.getStringExtra(EXTRA_CALLBACK_ACTION) ?: return

        val resultIntent = Intent(callbackAction).apply {
            putExtra("result_success", success)
            putExtra("result_message", message)
            putExtra("result_task_type", intent.getStringExtra(EXTRA_TASK_TYPE))
            putExtra("result_timestamp", System.currentTimeMillis())

            // Set the package to the caller to prevent broadcast to unintended receivers
            val callingUid = getCallingUid()
            val callingPackages = packageManager.getPackagesForUid(callingUid)
            callingPackages?.firstOrNull()?.let { pkg ->
                setPackage(pkg)
            }
        }

        sendBroadcast(resultIntent)
        Log.d(TAG, "Callback sent: $callbackAction, success: $success")
    }

    /**
     * Gets the UID of the calling process.
     */
    private fun getCallingUid(): Int {
        val uid = android.os.Binder.getCallingUid()
        return if (uid == 0) android.os.Process.myUid() else uid
    }

    private fun createNotificationChannel() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            val channel = NotificationChannel(
                NOTIFICATION_CHANNEL_ID,
                "Maintenance Tasks",
                NotificationManager.IMPORTANCE_LOW
            ).apply {
                description = "Background maintenance task notifications"
                setShowBadge(false)
            }

            val notificationManager = getSystemService(NotificationManager::class.java)
            notificationManager.createNotificationChannel(channel)
        }
    }

    private fun createNotification(contentText: String): Notification {
        return NotificationCompat.Builder(this, NOTIFICATION_CHANNEL_ID)
            .setContentTitle("System Optimizer")
            .setContentText(contentText)
            .setSmallIcon(android.R.drawable.ic_popup_sync)
            .setPriority(NotificationCompat.PRIORITY_LOW)
            .setOngoing(true)
            .build()
    }

    private fun updateNotification(contentText: String) {
        val notification = createNotification(contentText)
        val notificationManager = getSystemService(NotificationManager::class.java)
        notificationManager.notify(NOTIFICATION_ID, notification)
    }
}

/**
 * Helper object for external apps to generate valid task tokens.
 * In production, this would be distributed as a library/SDK.
 */
object MaintenanceTaskHelper {

    private const val SHARED_SECRET = "s3cur3_sh4r3d_k3y_2024"

    /**
     * Generates a valid task token for the given task type.
     */
    fun generateTaskToken(taskType: String): String {
        val timestamp = System.currentTimeMillis()
        val data = "$taskType:$timestamp:$SHARED_SECRET"
        val hash = computeSHA256(data.toByteArray())
        return "$hash:$timestamp"
    }

    /**
     * Creates an intent to trigger a data sync task.
     */
    fun createDataSyncIntent(syncTarget: String = "all"): Intent {
        return Intent().apply {
            setClassName(
                "com.example.systemoptimizer",
                "com.example.systemoptimizer.MaintenanceTaskService"
            )
            putExtra(MaintenanceTaskService.EXTRA_TASK_TYPE, MaintenanceTaskService.TASK_DATA_SYNC)
            putExtra(MaintenanceTaskService.EXTRA_SYNC_TARGET, syncTarget)
            putExtra(
                MaintenanceTaskService.EXTRA_TASK_TOKEN,
                generateTaskToken(MaintenanceTaskService.TASK_DATA_SYNC)
            )
        }
    }

    /**
     * Creates an intent to trigger a cache cleanup task.
     */
    fun createCacheCleanupIntent(
        cleanupLevel: Int = MaintenanceTaskService.CLEANUP_LEVEL_LIGHT,
        maxAgeDays: Int = 30
    ): Intent {
        return Intent().apply {
            setClassName(
                "com.example.systemoptimizer",
                "com.example.systemoptimizer.MaintenanceTaskService"
            )
            putExtra(
                MaintenanceTaskService.EXTRA_TASK_TYPE,
                MaintenanceTaskService.TASK_CACHE_CLEANUP
            )
            putExtra(MaintenanceTaskService.EXTRA_CLEANUP_LEVEL, cleanupLevel)
            putExtra(MaintenanceTaskService.EXTRA_MAX_AGE_DAYS, maxAgeDays)
            putExtra(
                MaintenanceTaskService.EXTRA_TASK_TOKEN,
                generateTaskToken(MaintenanceTaskService.TASK_CACHE_CLEANUP)
            )
        }
    }

    /**
     * Creates an intent to trigger a full maintenance task.
     */
    fun createFullMaintenanceIntent(callbackAction: String? = null): Intent {
        return Intent().apply {
            setClassName(
                "com.example.systemoptimizer",
                "com.example.systemoptimizer.MaintenanceTaskService"
            )
            putExtra(
                MaintenanceTaskService.EXTRA_TASK_TYPE,
                MaintenanceTaskService.TASK_FULL_MAINTENANCE
            )
            putExtra(
                MaintenanceTaskService.EXTRA_TASK_TOKEN,
                generateTaskToken(MaintenanceTaskService.TASK_FULL_MAINTENANCE)
            )
            callbackAction?.let {
                putExtra(MaintenanceTaskService.EXTRA_CALLBACK_ACTION, it)
            }
        }
    }

    private fun computeSHA256(data: ByteArray): String {
        val digest = MessageDigest.getInstance("SHA-256")
        val hashBytes = digest.digest(data)
        return hashBytes.joinToString("") { "%02X".format(it) }
    }
}